const inputData = $input.first().json;

function extractTextContent(raw) {
  if (typeof raw === 'string') return raw;
  if (Array.isArray(raw)) {
    for (const item of raw) {
      if (item?.output) return item.output;
      if (item?.text)   return item.text;
      if (item?.content) return item.content;
    }
    return JSON.stringify(raw[0] || '');
  }
  return raw?.output || raw?.text || raw?.content || raw?.message || JSON.stringify(raw);
}

function getField(text, key) {
  const m = text.match(new RegExp(`^${key}:\\s*(.+)$`, 'm'));
  return m ? m[1].trim() : null;
}

function getSection(text, name) {
  const escaped = name.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const m = text.match(
    new RegExp(`===SECTION:\\s*${escaped}===\\s*\\n([\\s\\S]*?)(?===SECTION:|===END_REPORT===|$)`, 'i')
  );
  return m ? m[1].trim() : null;
}

function parseThemes(section, actionKey) {
  if (!section) return [];
  const themes = [];
  const blocks = section.split(/THEME_START\s*/i).slice(1);

  for (const block of blocks) {
    const end = block.indexOf('THEME_END');
    const body = end !== -1 ? block.substring(0, end) : block;

    const theme = {};

    const title = getField(body, 'THEME_TITLE');
    if (!title) continue;
    theme.title = title;

    const freq = getField(body, 'THEME_FREQUENCY');
    if (freq) theme.frequency = parseInt(freq) || freq;

    const signal = getField(body, 'THEME_SIGNAL');
    if (signal) theme.signal_strength = signal;

    const quotes = [];
    for (let i = 1; i <= 6; i++) {
      const q = getField(body, `THEME_QUOTE_${i}`);
      if (q) quotes.push(q);
    }
    if (quotes.length) theme.example_comments = quotes;

    const insight     = getField(body, 'THEME_INSIGHT');
    const response    = getField(body, 'THEME_RESPONSE');
    const correction  = getField(body, 'THEME_CORRECTION');
    const opportunity = getField(body, 'THEME_OPPORTUNITY');
    const strategy    = getField(body, 'THEME_STRATEGY');
    const description = getField(body, 'THEME_DESCRIPTION');

    if (insight)     theme.why_it_matters        = insight;
    if (response)    theme.recommended_response  = response;
    if (correction)  theme.correction_opportunity = correction;
    if (opportunity) theme.content_opportunity   = opportunity;
    if (strategy)    theme.strategic_implication = strategy;
    if (description) theme.description           = description;

    themes.push(theme);
  }
  return themes;
}

function parsePostIdentification(text) {
  const result = {};
  const fields = {
    post_url:          'POST_URL',
    post_id:           'POST_ID',
    platform:          'POST_PLATFORM',
    total_comments:    'POST_TOTAL_COMMENTS',
    comments_analyzed: 'POST_COMMENTS_ANALYZED',
    report_title:      'REPORT_TITLE'
  };
  for (const [key, field] of Object.entries(fields)) {
    const val = getField(text, field);
    if (val) {
      result[key] = (key === 'total_comments' || key === 'comments_analyzed')
        ? (parseInt(val) || val) : val;
    }
  }
  return Object.keys(result).length > 0 ? result : null;
}

function parsePerformanceSignal(text) {
  const section = getSection(text, 'POST PERFORMANCE');
  if (!section) return null;

  const result = {};

  const platform = getField(section, 'PLATFORM');
  if (platform) result.platforms = [platform];

  const total = getField(section, 'TOTAL_ANALYZED');
  if (total) result.total_comments_analyzed = parseInt(total);

  const topComments = [];
  for (let i = 1; i <= 5; i++) {
    const c = getField(section, `TOP_COMMENT_${i}`);
    if (c) topComments.push(c);
  }
  if (topComments.length) result.top_engagement_comments = topComments;

  const topThreads = [];
  for (let i = 1; i <= 5; i++) {
    const t = getField(section, `TOP_THREAD_${i}`);
    if (t) topThreads.push(t);
  }
  if (topThreads.length) result.most_active_threads = topThreads;

  const sentiment = {};
  const sentFields = {
    positive:  'SENTIMENT_POSITIVE',
    skeptical: 'SENTIMENT_SKEPTICAL',
    neutral:   'SENTIMENT_NEUTRAL',
    humorous:  'SENTIMENT_HUMOROUS'
  };
  for (const [key, field] of Object.entries(sentFields)) {
    const val = getField(section, field);
    if (val) sentiment[key] = parseInt(val);
  }
  if (Object.keys(sentiment).length) result.sentiment_distribution = sentiment;

  return Object.keys(result).length > 0 ? result : null;
}

function parseSophistication(text) {
  const section = getSection(text, 'AUDIENCE SOPHISTICATION');
  if (!section) return null;

  const result = {
    cluster_id: 'C5',
    cluster_name: 'Audience Sophistication Assessment'
  };

  const score = getField(section, 'SCORE');
  if (score) {
    const parts = score.split('/');
    result.score = parseFloat(parts[0].trim());
    result.score_out_of = parseInt(parts[1]?.trim()) || 5;
  }

  const just = getField(section, 'JUSTIFICATION');
  if (just) result.justification = just;

  const breakdown = {};
  const b = getField(section, 'BEGINNER_PCT');
  const i = getField(section, 'INTERMEDIATE_PCT');
  const a = getField(section, 'ADVANCED_PCT');
  if (b) breakdown.beginner_pct     = parseInt(b);
  if (i) breakdown.intermediate_pct = parseInt(i);
  if (a) breakdown.advanced_pct     = parseInt(a);
  if (Object.keys(breakdown).length) result.audience_breakdown = breakdown;

  const implications = [];
  for (let n = 1; n <= 6; n++) {
    const imp = getField(section, `IMPLICATION_${n}`);
    if (imp) implications.push(imp);
  }
  if (implications.length) result.implications_for_messaging = implications;

  return Object.keys(result).length > 2 ? result : null;
}

function parseStrategicSummary(text) {
  const section = getSection(text, 'STRATEGIC SUMMARY');
  if (!section) return null;

  const sentences = [];
  for (let i = 1; i <= 5; i++) {
    const s = getField(section, `SENTENCE_${i}`);
    if (s) sentences.push(s);
  }
  return sentences.length ? sentences.join(' ') : null;
}

function parseActions(text) {
  const section = getSection(text, 'ACTION RECOMMENDATIONS');
  if (!section) return null;

  const actions = [];
  for (let i = 1; i <= 12; i++) {
    const priority       = getField(section, `ACTION_${i}_PRIORITY`);
    const func           = getField(section, `ACTION_${i}_FUNCTION`);
    const recommendation = getField(section, `ACTION_${i}_RECOMMENDATION`);
    if (priority && func && recommendation) {
      actions.push({
        priority: parseInt(priority),
        function: func,
        recommendation
      });
    }
  }

  return actions.length
    ? { total_actions: actions.length, actions: actions.sort((a, b) => a.priority - b.priority) }
    : null;
}

function buildMetadata(text, postId, platforms) {
  const now = new Date();
  const meta = {
    report_generated_at: now.toISOString(),
    report_generated_date: now.toLocaleDateString('en-US', {
      year: 'numeric', month: 'long', day: 'numeric'
    }),
    analysis_version: '5.0.0',
    analysis_type: 'Social Media Comment Intelligence Report'
  };
  if (platforms?.length)    meta.platforms_detected = platforms;
  if (postId?.post_id)      meta.post_id            = postId.post_id;
  if (postId?.post_url)     meta.post_url           = postId.post_url;
  if (postId?.platform)     meta.platform           = postId.platform;
  if (postId?.report_title) meta.report_title       = postId.report_title;
  if (postId?.total_comments)    meta.total_comments    = postId.total_comments;
  if (postId?.comments_analyzed) meta.comments_analyzed = postId.comments_analyzed;
  return meta;
}

function parseReport(rawText) {
  const postId      = parsePostIdentification(rawText);
  const performance = parsePerformanceSignal(rawText);
  const platforms   = performance?.platforms || null;
  const metadata    = buildMetadata(rawText, postId, platforms);

  const c1themes = parseThemes(getSection(rawText, 'QUESTIONS PROSPECTS ARE ASKING'));
  const c2themes = parseThemes(getSection(rawText, 'PURCHASE OBJECTIONS'));
  const c3themes = parseThemes(getSection(rawText, 'MISCONCEPTIONS'));
  const c4themes = parseThemes(getSection(rawText, 'CURIOSITY SIGNALS'));
  const c5        = parseSophistication(rawText);
  const c6themes = parseThemes(getSection(rawText, 'EMERGING THEMES'));

  const clusters = {};

  if (c1themes.length) clusters.cluster_1_questions_asked = {
    cluster_id: 'C1',
    cluster_name: 'Questions Prospects Are Asking',
    total_themes: c1themes.length,
    themes: c1themes
  };

  if (c2themes.length) clusters.cluster_2_purchase_objections = {
    cluster_id: 'C2',
    cluster_name: 'Purchase Objections',
    total_themes: c2themes.length,
    themes: c2themes
  };

  if (c3themes.length) clusters.cluster_3_misconceptions = {
    cluster_id: 'C3',
    cluster_name: 'Misconceptions About the Product or Category',
    total_themes: c3themes.length,
    themes: c3themes
  };

  if (c4themes.length) clusters.cluster_4_curiosity_signals = {
    cluster_id: 'C4',
    cluster_name: 'Curiosity Signals',
    total_themes: c4themes.length,
    themes: c4themes
  };

  if (c5) clusters.cluster_5_audience_sophistication = c5;

  if (c6themes.length) clusters.cluster_6_emerging_themes = {
    cluster_id: 'C6',
    cluster_name: 'Emerging Conversation Themes',
    total_themes: c6themes.length,
    themes: c6themes
  };

  const summary = parseStrategicSummary(rawText);
  const actions = parseActions(rawText);

  const report = { metadata };
  if (postId)                       report.post_identification              = postId;
  if (performance)                  report.post_performance_signal          = performance;
  if (Object.keys(clusters).length) report.intelligence_clusters            = clusters;
  if (summary)                      report.strategic_intelligence_summary   = summary;
  if (actions)                      report.immediate_action_recommendations = actions;

  return report;
}

let rawText = '';

try {
  rawText = extractTextContent(
    inputData.output  ??
    inputData.text    ??
    inputData.content ??
    inputData.message ??
    inputData
  );

  if (!rawText || rawText.trim().length < 50) {
    throw new Error('Input text is empty or too short to parse.');
  }

  const report = parseReport(rawText);
  return [{ json: { success: true, report } }];

} catch (error) {
  return [{
    json: {
      success: false,
      error: {
        message: error.message,
        timestamp: new Date().toISOString(),
        raw_input_preview: rawText ? rawText.substring(0, 300) + '...' : 'No input received'
      },
      report: null
    }
  }];
}

const data = $input.first().json;
const report = data.report || {};
const metadata = report.metadata || {};
const postId = report.post_identification || {};
const clusters = report.intelligence_clusters || {};
const perf = report.post_performance_signal || null;
const summary = report.strategic_intelligence_summary || null;
const actions = report.immediate_action_recommendations?.actions || [];

/* ============================================================
   HELPERS
   ============================================================ */

function esc(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

function platformColor(platform) {
  const colors = {
    'instagram': '#E1306C',
    'tiktok':    '#010101',
    'facebook':  '#1877F2',
    'youtube':   '#FF0000',
    'twitter':   '#1DA1F2'
  };
  return colors[(platform || '').toLowerCase()] || '#1a73e8';
}

function platformIcon(platform) {
  const icons = {
    'instagram': '📸',
    'tiktok':    '🎵',
    'facebook':  '👥',
    'youtube':   '▶️',
    'twitter':   '🐦'
  };
  return icons[(platform || '').toLowerCase()] || '🌐';
}

function signalColor(signal) {
  if (!signal) return '#888';
  const s = signal.toLowerCase();
  if (s.includes('very strong')) return '#2e7d32';
  if (s.includes('strong'))      return '#1a73e8';
  if (s.includes('moderate'))    return '#f57c00';
  if (s.includes('weak'))        return '#e53935';
  return '#888';
}

function signalDot(signal) {
  const color = signalColor(signal);
  return `<span style="display:inline-flex;align-items:center;gap:5px;padding:3px 10px;
    border-radius:20px;font-size:11px;font-weight:700;background:${color}15;
    color:${color};border:1px solid ${color}40;">
    <span style="width:6px;height:6px;border-radius:50%;background:${color};display:inline-block;"></span>
    ${esc(signal || 'N/A')}
  </span>`;
}

function badge(text, color) {
  return `<span style="display:inline-block;padding:4px 12px;border-radius:20px;
    font-size:12px;font-weight:600;background:${color};color:#fff;margin:2px 3px 2px 0;">
    ${esc(text)}
  </span>`;
}

function progressBar(label, pct, color, showPct = true) {
  const safe = Math.min(100, Math.max(0, pct || 0));
  return `
    <div style="margin:10px 0;">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:5px;">
        <span style="font-size:13px;color:#555;font-weight:500;">${esc(label)}</span>
        ${showPct ? `<span style="font-size:13px;font-weight:700;color:${color};">${safe}%</span>` : ''}
      </div>
      <div style="background:#f0f0f0;border-radius:20px;height:10px;overflow:hidden;">
        <div style="width:${safe}%;background:linear-gradient(90deg,${color},${color}99);
          height:10px;border-radius:20px;transition:width 0.3s;"></div>
      </div>
    </div>`;
}

function scoreRing(score, maxScore, color) {
  const pct = (score / maxScore) * 100;
  const r = 42;
  const circ = 2 * Math.PI * r;
  const offset = circ - (pct / 100) * circ;
  return `
    <div style="position:relative;width:120px;height:120px;flex-shrink:0;">
      <svg width="120" height="120" viewBox="0 0 120 120">
        <circle cx="60" cy="60" r="${r}" fill="none" stroke="#f0f0f0" stroke-width="10"/>
        <circle cx="60" cy="60" r="${r}" fill="none" stroke="${color}" stroke-width="10"
          stroke-dasharray="${circ}" stroke-dashoffset="${offset}"
          stroke-linecap="round" transform="rotate(-90 60 60)"/>
      </svg>
      <div style="position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);
        text-align:center;">
        <div style="font-size:26px;font-weight:900;color:${color};">${score}</div>
        <div style="font-size:10px;color:#999;">/ ${maxScore}</div>
      </div>
    </div>`;
}

function statCard(value, label, color, icon = '') {
  return `
    <div style="background:#fff;border-radius:12px;padding:20px;text-align:center;
      box-shadow:0 2px 12px rgba(0,0,0,0.06);flex:1;min-width:120px;
      border-top:3px solid ${color};">
      ${icon ? `<div style="font-size:20px;margin-bottom:6px;">${icon}</div>` : ''}
      <div style="font-size:28px;font-weight:900;color:${color};line-height:1.1;">${esc(String(value))}</div>
      <div style="font-size:12px;color:#888;margin-top:4px;font-weight:500;">${esc(label)}</div>
    </div>`;
}

function commentBubble(text, highlight = false) {
  return `
    <div style="background:${highlight ? '#fff8e1' : '#f8f9ff'};
      border-left:3px solid ${highlight ? '#f57c00' : '#a8c4ff'};
      border-radius:0 8px 8px 0;padding:10px 14px;margin:6px 0;
      font-style:italic;color:#444;font-size:13.5px;line-height:1.5;">
      "${esc(text)}"
    </div>`;
}

function sectionDivider(icon, title, subtitle = '', color = '#1a73e8') {
  return `
    <div style="margin:48px 0 20px;">
      <div style="display:flex;align-items:center;gap:12px;margin-bottom:6px;">
        <div style="width:40px;height:40px;border-radius:10px;background:${color}15;
          display:flex;align-items:center;justify-content:center;font-size:20px;flex-shrink:0;">
          ${icon}
        </div>
        <div>
          <h2 style="margin:0;font-size:20px;color:#1a1a2e;font-weight:800;">${esc(title)}</h2>
          ${subtitle ? `<p style="margin:2px 0 0;font-size:13px;color:#888;">${esc(subtitle)}</p>` : ''}
        </div>
      </div>
      <div style="height:2px;background:linear-gradient(90deg,${color},${color}00);
        border-radius:2px;margin-top:10px;"></div>
    </div>`;
}

const CLUSTER_CONFIG = {
  cluster_1_questions_asked:         { icon:'❓', color:'#1a73e8', label:'Questions Prospects Are Asking',        actionKey:'why_it_matters',         actionIcon:'⚡', actionLabel:'Why It Matters' },
  cluster_2_purchase_objections:     { icon:'🚧', color:'#e53935', label:'Purchase Objections',                  actionKey:'recommended_response',   actionIcon:'💬', actionLabel:'Recommended Response' },
  cluster_3_misconceptions:          { icon:'💡', color:'#f57c00', label:'Misconceptions',                       actionKey:'correction_opportunity', actionIcon:'🔧', actionLabel:'Correction Opportunity' },
  cluster_4_curiosity_signals:       { icon:'🔍', color:'#00897b', label:'Curiosity Signals',                    actionKey:'content_opportunity',    actionIcon:'🎯', actionLabel:'Content Opportunity' },
  cluster_5_audience_sophistication: { icon:'🎓', color:'#7b1fa2', label:'Audience Sophistication',              actionKey:null,                     actionIcon:'',   actionLabel:'' },
  cluster_6_emerging_themes:         { icon:'🌱', color:'#2e7d32', label:'Emerging Conversation Themes',         actionKey:'strategic_implication',  actionIcon:'🧠', actionLabel:'Strategic Implication' }
};

const ACTION_COLORS = ['#e53935','#e53935','#f57c00','#f57c00','#1a73e8','#1a73e8','#00897b','#00897b','#7b1fa2','#7b1fa2'];

/* ============================================================
   SECTION BUILDERS
   ============================================================ */

function buildHeader() {
  const title   = postId.report_title || metadata.report_title || 'Social Media Intelligence Report';
  const date    = metadata.report_generated_date || '';
  const url     = postId.post_url || metadata.post_url || '';
  const pid     = postId.post_id || metadata.post_id || '';
  const plats   = metadata.platforms_detected || (metadata.platform ? [metadata.platform] : []);
  const totalC  = postId.total_comments || metadata.total_comments || '';
  const analyzed = postId.comments_analyzed || metadata.comments_analyzed || '';

  const platformBadges = plats.map(p =>
    `<span style="display:inline-flex;align-items:center;gap:5px;padding:4px 12px;
      border-radius:20px;font-size:12px;font-weight:700;
      background:${platformColor(p)};color:#fff;margin:2px 3px;">
      ${platformIcon(p)} ${esc(p)}
    </span>`
  ).join('');

  return `
    <div style="background:linear-gradient(135deg,#0f0c29 0%,#1a1a2e 50%,#16213e 100%);
      border-radius:20px;padding:40px 44px;margin-bottom:36px;color:#fff;
      box-shadow:0 8px 32px rgba(0,0,0,0.2);">

      <div style="display:flex;align-items:center;gap:8px;margin-bottom:14px;">
        <span style="font-size:11px;font-weight:700;opacity:0.5;text-transform:uppercase;
          letter-spacing:2px;">Market Intelligence Report</span>
      </div>

      <h1 style="margin:0 0 16px;font-size:24px;font-weight:900;line-height:1.3;
        background:linear-gradient(90deg,#fff,#a8c4ff);-webkit-background-clip:text;
        -webkit-text-fill-color:transparent;background-clip:text;">
        ${esc(title)}
      </h1>

      <div style="display:flex;flex-wrap:wrap;gap:8px;margin-bottom:20px;">
        ${platformBadges}
      </div>

      <div style="display:flex;flex-wrap:wrap;gap:24px;padding-top:16px;
        border-top:1px solid rgba(255,255,255,0.1);">
        ${date    ? `<div style="font-size:13px;opacity:0.7;">📅 <strong>${esc(date)}</strong></div>` : ''}
        ${totalC  ? `<div style="font-size:13px;opacity:0.7;">💬 <strong>${esc(String(totalC))}</strong> total comments</div>` : ''}
        ${analyzed? `<div style="font-size:13px;opacity:0.7;">🔍 <strong>${esc(String(analyzed))}</strong> analyzed</div>` : ''}
        ${pid     ? `<div style="font-size:13px;opacity:0.7;">🆔 Post ID: <code style="background:rgba(255,255,255,0.1);padding:1px 6px;border-radius:4px;">${esc(pid)}</code></div>` : ''}
        ${url     ? `<div style="font-size:13px;opacity:0.7;">🔗 <a href="${esc(url)}" style="color:#a8c4ff;" target="_blank">View Original Post</a></div>` : ''}
      </div>
    </div>`;
}

function buildPerformanceSignal() {
  if (!perf) return '';

  const plats = perf.platforms || [];
  const sentiment = perf.sentiment_distribution || {};
  const topComments = perf.top_engagement_comments || [];
  const threads = perf.most_active_threads || [];

  let html = sectionDivider('🔴', 'Post Performance Signal', 'Engagement metrics and sentiment analysis', '#e53935');

  // Stat row
  const stats = [];
  if (perf.total_comments_analyzed) stats.push(statCard(perf.total_comments_analyzed, 'Comments Analyzed', '#1a73e8', '💬'));
  if (plats.length)                  stats.push(statCard(plats.length, plats.length > 1 ? 'Platforms' : 'Platform', '#00897b', '🌐'));
  if (Object.keys(sentiment).length) {
    const topSent = Object.entries(sentiment).sort((a,b) => b[1]-a[1])[0];
    if (topSent) stats.push(statCard(topSent[1] + '%', 'Top Sentiment: ' + topSent[0].charAt(0).toUpperCase() + topSent[0].slice(1), '#f57c00', '📊'));
  }
  if (topComments.length) stats.push(statCard(topComments.length, 'Top Engaged Comments', '#7b1fa2', '⭐'));

  if (stats.length) {
    html += `<div style="display:flex;flex-wrap:wrap;gap:16px;margin-bottom:24px;">${stats.join('')}</div>`;
  }

  // Two column layout
  html += `<div style="display:grid;grid-template-columns:1fr 1fr;gap:20px;margin-bottom:20px;">`;

  // Top comments
  if (topComments.length) {
    html += `<div style="background:#fff;border-radius:14px;padding:20px;
      box-shadow:0 2px 12px rgba(0,0,0,0.06);">
      <div style="font-size:13px;font-weight:800;color:#1a1a2e;text-transform:uppercase;
        letter-spacing:0.5px;margin-bottom:14px;display:flex;align-items:center;gap:6px;">
        ⭐ Top Engagement Comments
      </div>`;
    topComments.forEach((c, i) => {
      html += `<div style="display:flex;gap:10px;margin-bottom:10px;align-items:flex-start;">
        <span style="min-width:22px;height:22px;border-radius:50%;background:#1a73e8;
          color:#fff;font-size:11px;font-weight:800;display:flex;align-items:center;
          justify-content:center;flex-shrink:0;">${i+1}</span>
        <div style="font-size:13px;color:#444;line-height:1.4;">${esc(c)}</div>
      </div>`;
    });
    html += `</div>`;
  }

  // Sentiment chart
  if (Object.keys(sentiment).length) {
    const sentColors = { positive:'#2e7d32', skeptical:'#e53935', neutral:'#1a73e8', humorous:'#f57c00' };
    html += `<div style="background:#fff;border-radius:14px;padding:20px;
