// Normalize username → URL
function normalizeTarget(platform, target) {
  if (!target) return null;

  target = target.trim();

  // Already a full URL
  if (target.startsWith('http')) return cleanUrl(platform, target);

  // Remove @ if exists
  const username = target.replace(/^@/, '');

  switch (platform) {
    case 'instagram':
      return `https://www.instagram.com/${username}/`;

    case 'tiktok':
      return `https://www.tiktok.com/@${username}`;

    case 'facebook':
      return `https://www.facebook.com/${username}`;

    default:
      return target;
  }
}

// Clean URLs (especially FB share links)
function cleanUrl(platform, url) {
  try {
    const u = new URL(url);

    // Remove tracking params
    u.search = '';

    // Special handling for Facebook share links
    if (platform === 'facebook' && u.pathname.includes('/share/')) {
      return url; // keep as-is (important for scraping sometimes)
    }

    return u.toString();
  } catch (e) {
    return url;
  }
}

// MAIN
const body = $json.body || {};
let targets = [];

// Handle both input types
if (Array.isArray(body.targets)) {
  targets = body.targets;
} else if (body.platform && body.target) {
  targets = [body];
}

// Process dynamically
const output = [];

for (const item of targets) {
  const platform = (item.platform || '').toLowerCase();
  const rawTarget = item.target;

  if (!platform || !rawTarget) continue;

  const finalUrl = normalizeTarget(platform, rawTarget);

  output.push({
    platform,
    url: finalUrl,
    original: rawTarget
  });
}

// Return dynamic items
return output.map(i => ({ json: i }));
